import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import '../styles/ApplyPage.css';

const ApplyPage = () => {
    const { t } = useTranslation();
    const [currentStep, setCurrentStep] = useState(1);
    const [formData, setFormData] = useState({
        // Personal Information
        firstName: '',
        lastName: '',
        email: '',
        phone: '',
        dateOfBirth: '',
        nationality: '',
        address: '',
        city: '',
        postalCode: '',
        
        // Educational Background
        highestEducation: '',
        institutionName: '',
        graduationYear: '',
        gpa: '',
        major: '',
        
        // Program Selection
        selectedProgram: '',
        startDate: '',
        studyMode: '',
        
        // Work Experience
        hasWorkExperience: '',
        currentEmployment: '',
        workExperience: '',
        
        // Additional Information
        motivation: '',
        goals: '',
        hearAboutUs: '',
        additionalInfo: ''
    });
    const [errors, setErrors] = useState({});
    const [isSubmitting, setIsSubmitting] = useState(false);

    // Keep ALL your existing useEffect and functions exactly as they are
    useEffect(() => {
        // Add animation when component mounts
        const sections = document.querySelectorAll('.apply-section');
        sections.forEach((section, index) => {
            setTimeout(() => {
                section.classList.add('animate-in');
            }, index * 100);
        });
    }, []);

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: value
        }));
        
        // Clear error when user starts typing
        if (errors[name]) {
            setErrors(prev => ({
                ...prev,
                [name]: ''
            }));
        }
    };

    const validateStep = (step) => {
        const newErrors = {};
        
        switch (step) {
            case 1:
                if (!formData.firstName.trim()) newErrors.firstName = t('apply.validation.firstNameRequired');
                if (!formData.lastName.trim()) newErrors.lastName = t('apply.validation.lastNameRequired');
                if (!formData.email.trim()) newErrors.email = t('apply.validation.emailRequired');
                if (!formData.phone.trim()) newErrors.phone = t('apply.validation.phoneRequired');
                if (!formData.dateOfBirth) newErrors.dateOfBirth = t('apply.validation.dobRequired');
                if (!formData.nationality.trim()) newErrors.nationality = t('apply.validation.nationalityRequired');
                break;
            case 2:
                if (!formData.highestEducation) newErrors.highestEducation = t('apply.validation.educationRequired');
                if (!formData.institutionName.trim()) newErrors.institutionName = t('apply.validation.institutionRequired');
                if (!formData.graduationYear) newErrors.graduationYear = t('apply.validation.yearRequired');
                break;
            case 3:
                if (!formData.selectedProgram) newErrors.selectedProgram = t('apply.validation.programRequired');
                if (!formData.startDate) newErrors.startDate = t('apply.validation.startDateRequired');
                if (!formData.studyMode) newErrors.studyMode = t('apply.validation.studyModeRequired');
                break;
            case 4:
                if (!formData.motivation.trim()) newErrors.motivation = t('apply.validation.motivationRequired');
                if (!formData.goals.trim()) newErrors.goals = t('apply.validation.goalsRequired');
                break;
        }
        
        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const nextStep = () => {
        if (validateStep(currentStep)) {
            setCurrentStep(prev => Math.min(prev + 1, 4));
        }
    };

    const prevStep = () => {
        setCurrentStep(prev => Math.max(prev - 1, 1));
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        
        if (!validateStep(currentStep)) {
            return;
        }
        
        setIsSubmitting(true);
        
        try {
            // Simulate API call
            await new Promise(resolve => setTimeout(resolve, 2000));
            
            // Success - show confirmation
            alert(t('apply.successMessage'));
            
            // Reset form
            setFormData({
                firstName: '',
                lastName: '',
                email: '',
                phone: '',
                dateOfBirth: '',
                nationality: '',
                address: '',
                city: '',
                postalCode: '',
                highestEducation: '',
                institutionName: '',
                graduationYear: '',
                gpa: '',
                major: '',
                selectedProgram: '',
                startDate: '',
                studyMode: '',
                hasWorkExperience: '',
                currentEmployment: '',
                workExperience: '',
                motivation: '',
                goals: '',
                hearAboutUs: '',
                additionalInfo: ''
            });
            setCurrentStep(1);
            
        } catch (error) {
            console.error('Submission error:', error);
            alert(t('apply.errorMessage'));
        } finally {
            setIsSubmitting(false);
        }
    };

    const renderStepContent = () => {
        switch (currentStep) {
            case 1:
                return (
                    <div className="step-content">
                        <h3 className="text-gray-900 dark:text-white transition-colors duration-300">{t('apply.steps.personal.title')}</h3>
                        <p className="text-gray-600 dark:text-gray-300 transition-colors duration-300">{t('apply.steps.personal.description')}</p>
                        
                        <div className="form-grid">
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.firstName')} *</label>
                                <input
                                    type="text"
                                    name="firstName"
                                    value={formData.firstName}
                                    onChange={handleInputChange}
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.firstName ? 'border-red-500 dark:border-red-400' : ''}`}
                                    placeholder={t('apply.placeholders.firstName')}
                                />
                                {errors.firstName && <span className="error-message text-red-500 dark:text-red-400">{errors.firstName}</span>}
                            </div>
                            
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.lastName')} *</label>
                                <input
                                    type="text"
                                    name="lastName"
                                    value={formData.lastName}
                                    onChange={handleInputChange}
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.lastName ? 'border-red-500 dark:border-red-400' : ''}`}
                                    placeholder={t('apply.placeholders.lastName')}
                                />
                                {errors.lastName && <span className="error-message text-red-500 dark:text-red-400">{errors.lastName}</span>}
                            </div>
                            
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.email')} *</label>
                                <input
                                    type="email"
                                    name="email"
                                    value={formData.email}
                                    onChange={handleInputChange}
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.email ? 'border-red-500 dark:border-red-400' : ''}`}
                                    placeholder={t('apply.placeholders.email')}
                                />
                                {errors.email && <span className="error-message text-red-500 dark:text-red-400">{errors.email}</span>}
                            </div>
                            
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.phone')} *</label>
                                <input
                                    type="tel"
                                    name="phone"
                                    value={formData.phone}
                                    onChange={handleInputChange}
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.phone ? 'border-red-500 dark:border-red-400' : ''}`}
                                    placeholder={t('apply.placeholders.phone')}
                                />
                                {errors.phone && <span className="error-message text-red-500 dark:text-red-400">{errors.phone}</span>}
                            </div>
                            
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.dateOfBirth')} *</label>
                                <input
                                    type="date"
                                    name="dateOfBirth"
                                    value={formData.dateOfBirth}
                                    onChange={handleInputChange}
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.dateOfBirth ? 'border-red-500 dark:border-red-400' : ''}`}
                                />
                                {errors.dateOfBirth && <span className="error-message text-red-500 dark:text-red-400">{errors.dateOfBirth}</span>}
                            </div>
                            
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.nationality')} *</label>
                                <input
                                    type="text"
                                    name="nationality"
                                    value={formData.nationality}
                                    onChange={handleInputChange}
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.nationality ? 'border-red-500 dark:border-red-400' : ''}`}
                                    placeholder={t('apply.placeholders.nationality')}
                                />
                                {errors.nationality && <span className="error-message text-red-500 dark:text-red-400">{errors.nationality}</span>}
                            </div>
                            
                            <div className="form-group full-width">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.address')}</label>
                                <input
                                    type="text"
                                    name="address"
                                    value={formData.address}
                                    onChange={handleInputChange}
                                    className="bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300"
                                    placeholder={t('apply.placeholders.address')}
                                />
                            </div>
                            
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.city')}</label>
                                <input
                                    type="text"
                                    name="city"
                                    value={formData.city}
                                    onChange={handleInputChange}
                                    className="bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300"
                                    placeholder={t('apply.placeholders.city')}
                                />
                            </div>
                            
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.postalCode')}</label>
                                <input
                                    type="text"
                                    name="postalCode"
                                    value={formData.postalCode}
                                    onChange={handleInputChange}
                                    className="bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300"
                                    placeholder={t('apply.placeholders.postalCode')}
                                />
                            </div>
                        </div>
                    </div>
                );
            
            case 2:
                return (
                    <div className="step-content">
                        <h3 className="text-gray-900 dark:text-white transition-colors duration-300">{t('apply.steps.education.title')}</h3>
                        <p className="text-gray-600 dark:text-gray-300 transition-colors duration-300">{t('apply.steps.education.description')}</p>
                        
                        <div className="form-grid">
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.highestEducation')} *</label>
                                <select
                                    name="highestEducation"
                                    value={formData.highestEducation}
                                    onChange={handleInputChange}
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.highestEducation ? 'border-red-500 dark:border-red-400' : ''}`}
                                >
                                    <option value="" className="text-gray-500 dark:text-gray-400">{t('apply.placeholders.selectEducation')}</option>
                                    <option value="high-school" className="text-gray-900 dark:text-white">{t('apply.options.highSchool')}</option>
                                    <option value="associate" className="text-gray-900 dark:text-white">{t('apply.options.associate')}</option>
                                    <option value="bachelor" className="text-gray-900 dark:text-white">{t('apply.options.bachelor')}</option>
                                    <option value="master" className="text-gray-900 dark:text-white">{t('apply.options.master')}</option>
                                    <option value="doctorate" className="text-gray-900 dark:text-white">{t('apply.options.doctorate')}</option>
                                </select>
                                {errors.highestEducation && <span className="error-message text-red-500 dark:text-red-400">{errors.highestEducation}</span>}
                            </div>
                            
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.institutionName')} *</label>
                                <input
                                    type="text"
                                    name="institutionName"
                                    value={formData.institutionName}
                                    onChange={handleInputChange}
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.institutionName ? 'border-red-500 dark:border-red-400' : ''}`}
                                    placeholder={t('apply.placeholders.institutionName')}
                                />
                                {errors.institutionName && <span className="error-message text-red-500 dark:text-red-400">{errors.institutionName}</span>}
                            </div>
                            
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.graduationYear')} *</label>
                                <input
                                    type="number"
                                    name="graduationYear"
                                    value={formData.graduationYear}
                                    onChange={handleInputChange}
                                    min="1950"
                                    max={new Date().getFullYear() + 5}
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.graduationYear ? 'border-red-500 dark:border-red-400' : ''}`}
                                    placeholder="2024"
                                />
                                {errors.graduationYear && <span className="error-message text-red-500 dark:text-red-400">{errors.graduationYear}</span>}
                            </div>
                            
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.gpa')}</label>
                                <input
                                    type="text"
                                    name="gpa"
                                    value={formData.gpa}
                                    onChange={handleInputChange}
                                    className="bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300"
                                    placeholder={t('apply.placeholders.gpa')}
                                />
                            </div>
                            
                            <div className="form-group full-width">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.major')}</label>
                                <input
                                    type="text"
                                    name="major"
                                    value={formData.major}
                                    onChange={handleInputChange}
                                    className="bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300"
                                    placeholder={t('apply.placeholders.major')}
                                />
                            </div>
                        </div>
                    </div>
                );
            
            case 3:
                return (
                    <div className="step-content">
                        <h3 className="text-gray-900 dark:text-white transition-colors duration-300">{t('apply.steps.program.title')}</h3>
                        <p className="text-gray-600 dark:text-gray-300 transition-colors duration-300">{t('apply.steps.program.description')}</p>
                        
                        <div className="form-grid">
                            <div className="form-group full-width">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.selectedProgram')} *</label>
                                <select
                                    name="selectedProgram"
                                    value={formData.selectedProgram}
                                    onChange={handleInputChange}
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.selectedProgram ? 'border-red-500 dark:border-red-400' : ''}`}
                                >
                                    <option value="" className="text-gray-500 dark:text-gray-400">{t('apply.placeholders.selectProgram')}</option>
                                    <option value="web-development" className="text-gray-900 dark:text-white">{t('apply.programs.webDevelopment')}</option>
                                    <option value="data-science" className="text-gray-900 dark:text-white">{t('apply.programs.dataScience')}</option>
                                    <option value="cybersecurity" className="text-gray-900 dark:text-white">{t('apply.programs.cybersecurity')}</option>
                                    <option value="cloud-computing" className="text-gray-900 dark:text-white">{t('apply.programs.cloudComputing')}</option>
                                    <option value="ai-ml" className="text-gray-900 dark:text-white">{t('apply.programs.aiMl')}</option>
                                    <option value="mobile-development" className="text-gray-900 dark:text-white">{t('apply.programs.mobileDevelopment')}</option>
                                </select>
                                {errors.selectedProgram && <span className="error-message text-red-500 dark:text-red-400">{errors.selectedProgram}</span>}
                            </div>
                            
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.startDate')} *</label>
                                <select
                                    name="startDate"
                                    value={formData.startDate}
                                    onChange={handleInputChange}
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.startDate ? 'border-red-500 dark:border-red-400' : ''}`}
                                >
                                    <option value="" className="text-gray-500 dark:text-gray-400">{t('apply.placeholders.selectStartDate')}</option>
                                    <option value="2024-04" className="text-gray-900 dark:text-white">{t('apply.startDates.april2024')}</option>
                                    <option value="2024-07" className="text-gray-900 dark:text-white">{t('apply.startDates.july2024')}</option>
                                    <option value="2024-10" className="text-gray-900 dark:text-white">{t('apply.startDates.october2024')}</option>
                                    <option value="2025-01" className="text-gray-900 dark:text-white">{t('apply.startDates.january2025')}</option>
                                </select>
                                {errors.startDate && <span className="error-message text-red-500 dark:text-red-400">{errors.startDate}</span>}
                            </div>
                            
                            <div className="form-group">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.studyMode')} *</label>
                                <select
                                    name="studyMode"
                                    value={formData.studyMode}
                                    onChange={handleInputChange}
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.studyMode ? 'border-red-500 dark:border-red-400' : ''}`}
                                >
                                    <option value="" className="text-gray-500 dark:text-gray-400">{t('apply.placeholders.selectStudyMode')}</option>
                                    <option value="full-time" className="text-gray-900 dark:text-white">{t('apply.studyModes.fullTime')}</option>
                                    <option value="part-time" className="text-gray-900 dark:text-white">{t('apply.studyModes.partTime')}</option>
                                    <option value="online" className="text-gray-900 dark:text-white">{t('apply.studyModes.online')}</option>
                                </select>
                                {errors.studyMode && <span className="error-message text-red-500 dark:text-red-400">{errors.studyMode}</span>}
                            </div>
                            
                            <div className="form-group full-width">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.hasWorkExperience')}</label>
                                <div className="radio-group">
                                    <label className="radio-option text-gray-700 dark:text-gray-300 transition-colors duration-300">
                                        <input
                                            type="radio"
                                            name="hasWorkExperience"
                                            value="yes"
                                            checked={formData.hasWorkExperience === 'yes'}
                                            onChange={handleInputChange}
                                            className="accent-blue-500"
                                        />
                                        {t('apply.options.yes')}
                                    </label>
                                    <label className="radio-option text-gray-700 dark:text-gray-300 transition-colors duration-300">
                                        <input
                                            type="radio"
                                            name="hasWorkExperience"
                                            value="no"
                                            checked={formData.hasWorkExperience === 'no'}
                                            onChange={handleInputChange}
                                            className="accent-blue-500"
                                        />
                                        {t('apply.options.no')}
                                    </label>
                                </div>
                            </div>
                            
                            {formData.hasWorkExperience === 'yes' && (
                                <>
                                    <div className="form-group full-width">
                                        <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.currentEmployment')}</label>
                                        <input
                                            type="text"
                                            name="currentEmployment"
                                            value={formData.currentEmployment}
                                            onChange={handleInputChange}
                                            className="bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300"
                                            placeholder={t('apply.placeholders.currentEmployment')}
                                        />
                                    </div>
                                    
                                    <div className="form-group full-width">
                                        <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.workExperience')}</label>
                                        <textarea
                                            name="workExperience"
                                            value={formData.workExperience}
                                            onChange={handleInputChange}
                                            rows="4"
                                            className="bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300"
                                            placeholder={t('apply.placeholders.workExperience')}
                                        />
                                    </div>
                                </>
                            )}
                        </div>
                    </div>
                );
            
            case 4:
                return (
                    <div className="step-content">
                        <h3 className="text-gray-900 dark:text-white transition-colors duration-300">{t('apply.steps.additional.title')}</h3>
                        <p className="text-gray-600 dark:text-gray-300 transition-colors duration-300">{t('apply.steps.additional.description')}</p>
                        
                        <div className="form-grid">
                            <div className="form-group full-width">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.motivation')} *</label>
                                <textarea
                                    name="motivation"
                                    value={formData.motivation}
                                    onChange={handleInputChange}
                                    rows="4"
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.motivation ? 'border-red-500 dark:border-red-400' : ''}`}
                                    placeholder={t('apply.placeholders.motivation')}
                                />
                                {errors.motivation && <span className="error-message text-red-500 dark:text-red-400">{errors.motivation}</span>}
                            </div>
                            
                            <div className="form-group full-width">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.goals')} *</label>
                                <textarea
                                    name="goals"
                                    value={formData.goals}
                                    onChange={handleInputChange}
                                    rows="4"
                                    className={`bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300 ${errors.goals ? 'border-red-500 dark:border-red-400' : ''}`}
                                    placeholder={t('apply.placeholders.goals')}
                                />
                                {errors.goals && <span className="error-message text-red-500 dark:text-red-400">{errors.goals}</span>}
                            </div>
                            
                            <div className="form-group full-width">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.hearAboutUs')}</label>
                                <select
                                    name="hearAboutUs"
                                    value={formData.hearAboutUs}
                                    onChange={handleInputChange}
                                    className="bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300"
                                >
                                    <option value="" className="text-gray-500 dark:text-gray-400">{t('apply.placeholders.selectSource')}</option>
                                    <option value="google" className="text-gray-900 dark:text-white">{t('apply.sources.google')}</option>
                                    <option value="facebook" className="text-gray-900 dark:text-white">{t('apply.sources.facebook')}</option>
                                    <option value="instagram" className="text-gray-900 dark:text-white">{t('apply.sources.instagram')}</option>
                                    <option value="friend" className="text-gray-900 dark:text-white">{t('apply.sources.friend')}</option>
                                    <option value="website" className="text-gray-900 dark:text-white">{t('apply.sources.website')}</option>
                                    <option value="other" className="text-gray-900 dark:text-white">{t('apply.sources.other')}</option>
                                </select>
                            </div>
                            
                            <div className="form-group full-width">
                                <label className="text-gray-700 dark:text-gray-300 transition-colors duration-300">{t('apply.fields.additionalInfo')}</label>
                                <textarea
                                    name="additionalInfo"
                                    value={formData.additionalInfo}
                                    onChange={handleInputChange}
                                    rows="3"
                                    className="bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white placeholder-gray-500 dark:placeholder-gray-400 focus:border-blue-500 dark:focus:border-blue-400 transition-colors duration-300"
                                    placeholder={t('apply.placeholders.additionalInfo')}
                                />
                            </div>
                        </div>
                    </div>
                );
                
            default:
                return null;
        }
    };

    return (
        <div className="apply-page bg-gradient-to-br from-slate-50 to-gray-100 dark:from-gray-900 dark:to-slate-900 min-h-screen transition-colors duration-300">
            {/* Hero Section */}
            <section className="apply-hero bg-gradient-to-br from-blue-50 to-purple-50 dark:from-blue-900/20 dark:to-purple-900/20 transition-colors duration-300">
                <div className="container">
                    <div className="apply-hero-content apply-section">
                        <h1 className="text-gray-900 dark:text-white transition-colors duration-300">{t('apply.hero.title')}</h1>
                        <p className="text-gray-600 dark:text-gray-300 transition-colors duration-300">{t('apply.hero.description')}</p>
                        
                        <div className="application-stats">
                            <div className="stat-item bg-white/80 dark:bg-gray-800/80 backdrop-blur-sm border border-gray-200/50 dark:border-gray-700/50 transition-colors duration-300">
                                <span className="stat-number text-blue-600 dark:text-blue-400">93%</span>
                                <span className="stat-label text-gray-600 dark:text-gray-400">{t('apply.stats.acceptance')}</span>
                            </div>
                            <div className="stat-item bg-white/80 dark:bg-gray-800/80 backdrop-blur-sm border border-gray-200/50 dark:border-gray-700/50 transition-colors duration-300">
                                <span className="stat-number text-blue-600 dark:text-blue-400">2-3</span>
                                <span className="stat-label text-gray-600 dark:text-gray-400">{t('apply.stats.processing')}</span>
                            </div>
                            <div className="stat-item bg-white/80 dark:bg-gray-800/80 backdrop-blur-sm border border-gray-200/50 dark:border-gray-700/50 transition-colors duration-300">
                                <span className="stat-number text-blue-600 dark:text-blue-400">24/7</span>
                                <span className="stat-label text-gray-600 dark:text-gray-400">{t('apply.stats.support')}</span>
                            </div>
                        </div>
                    </div>
                </div>
            </section>

            {/* Application Form */}
            <section className="apply-form-section bg-white dark:bg-gray-800 transition-colors duration-300">
                <div className="container">
                    <div className="form-container bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 transition-colors duration-300">
                        {/* Progress Indicator */}
                        <div className="progress-indicator">
                            {[1, 2, 3, 4].map((step) => (
                                <div key={step} className="progress-step">
                                    <div className={`step-circle ${currentStep >= step ? 'active bg-blue-500 text-white' : 'bg-gray-200 dark:bg-gray-600 text-gray-600 dark:text-gray-400'} transition-colors duration-300`}>
                                        {currentStep > step ? (
                                            <span className="material-icons">check</span>
                                        ) : (
                                            step
                                        )}
                                    </div>
                                    <div className="step-label text-gray-600 dark:text-gray-400 transition-colors duration-300">
                                        {step === 1 && t('apply.steps.personal.label')}
                                        {step === 2 && t('apply.steps.education.label')}
                                        {step === 3 && t('apply.steps.program.label')}
                                        {step === 4 && t('apply.steps.additional.label')}
                                    </div>
                                    {step < 4 && (
                                        <div className={`step-line ${currentStep > step ? 'active bg-blue-500' : 'bg-gray-200 dark:bg-gray-600'} transition-colors duration-300`}></div>
                                    )}
                                </div>
                            ))}
                        </div>

                        {/* Form Content */}
                        <form onSubmit={handleSubmit} className="application-form">
                            {renderStepContent()}
                            
                            {/* Navigation Buttons */}
                            <div className="form-navigation">
                                {currentStep > 1 && (
                                    <button
                                        type="button"
                                        onClick={prevStep}
                                        className="btn btn-outline border-2 border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors duration-300"
                                    >
                                        <span className="material-icons">arrow_back</span>
                                        {t('apply.navigation.previous')}
                                    </button>
                                )}
                                
                                {currentStep < 4 ? (
                                    <button
                                        type="button"
                                        onClick={nextStep}
                                        className="btn btn-primary bg-gradient-to-r from-blue-500 to-purple-600 hover:from-blue-600 hover:to-purple-700 text-white transition-all duration-300"
                                    >
                                        {t('apply.navigation.next')}
                                        <span className="material-icons">arrow_forward</span>
                                    </button>
                                ) : (
                                    <button
                                        type="submit"
                                        disabled={isSubmitting}
                                        className="btn btn-primary bg-gradient-to-r from-green-500 to-blue-600 hover:from-green-600 hover:to-blue-700 text-white transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed"
                                    >
                                        {isSubmitting ? (
                                            <>
                                                <span className="loading-spinner"></span>
                                                {t('apply.navigation.submitting')}
                                            </>
                                        ) : (
                                            <>
                                                <span className="material-icons">send</span>
                                                {t('apply.navigation.submit')}
                                            </>
                                        )}
                                    </button>
                                )}
                            </div>
                        </form>
                    </div>
                </div>
            </section>

            {/* Additional Information */}
            <section className="apply-info bg-gray-50 dark:bg-gray-900 transition-colors duration-300">
                <div className="container">
                    <div className="info-grid">
                        <div className="info-card bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 hover:shadow-lg dark:hover:shadow-gray-900/20 transition-all duration-300">
                            <div className="info-icon bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400">
                                <span className="material-icons">help</span>
                            </div>
                            <h3 className="text-gray-900 dark:text-white transition-colors duration-300">{t('apply.info.help.title')}</h3>
                            <p className="text-gray-600 dark:text-gray-300 transition-colors duration-300">{t('apply.info.help.description')}</p>
                            <a href="/contact" className="info-link text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 transition-colors duration-300">
                                {t('apply.info.help.action')} <span className="material-icons">arrow_forward</span>
                            </a>
                        </div>
                        
                        <div className="info-card bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 hover:shadow-lg dark:hover:shadow-gray-900/20 transition-all duration-300">
                            <div className="info-icon bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400">
                                <span className="material-icons">school</span>
                            </div>
                            <h3 className="text-gray-900 dark:text-white transition-colors duration-300">{t('apply.info.programs.title')}</h3>
                            <p className="text-gray-600 dark:text-gray-300 transition-colors duration-300">{t('apply.info.programs.description')}</p>
                            <a href="/courses" className="info-link text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 transition-colors duration-300">
                                {t('apply.info.programs.action')} <span className="material-icons">arrow_forward</span>
                            </a>
                        </div>
                        
                        <div className="info-card bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 hover:shadow-lg dark:hover:shadow-gray-900/20 transition-all duration-300">
                            <div className="info-icon bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400">
                                <span className="material-icons">schedule</span>
                            </div>
                            <h3 className="text-gray-900 dark:text-white transition-colors duration-300">{t('apply.info.timeline.title')}</h3>
                            <p className="text-gray-600 dark:text-gray-300 transition-colors duration-300">{t('apply.info.timeline.description')}</p>
                            <span className="info-link text-gray-500 dark:text-gray-400">
                                {t('apply.info.timeline.detail')}
                            </span>
                        </div>
                    </div>
                </div>
            </section>
        </div>
    );
};

export default ApplyPage;
